mapper.select:
SELECT p.id AS stationId, p.station_name AS stationName, COUNT(*) AS totalCount, SUM(CASE WHEN a.status IN (4, 5) THEN 1 ELSE 0 END) AS handledCount, SUM(CASE WHEN a.first_response_at IS NOT NULL AND TIMESTAMPDIFF(SECOND, a.created_at, a.first_response_at) > CASE a.alarm_level WHEN 1 THEN 300 WHEN 2 THEN 600 ELSE 1800 END THEN 1 ELSE 0 END) AS timeoutCount FROM police_station p LEFT JOIN school_info s ON p.id = s.police_station_id LEFT JOIN alarm_record a ON s.id = a.school_id AND a.deleted = 0
p.deleted = 0
AND s.town_id = #{query.townId}
AND s.school_type = #{query.schoolType}
AND a.alarm_type = #{query.alarmType}
AND a.created_at >= #{query.startTime}
AND a.created_at <= #{query.endTime}
GROUP BY p.id, p.station_name ORDER BY totalCount DESC
